'use client';

import React from 'react';
import { useTheme } from '@/shared/hooks/useTheme';

interface DynamicSVGProps {
  children: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  width?: number | string;
  height?: number | string;
  viewBox?: string;
}

export default function DynamicSVG({ 
  children, 
  className, 
  style, 
  width, 
  height, 
  viewBox,
  ...props 
}: DynamicSVGProps) {
  return (
    <svg
      width={width}
      height={height}
      viewBox={viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      style={style}
      {...props}
    >
      {children}
    </svg>
  );
}

// Componente específico para elementos com stroke dinâmico
export function DynamicStrokeElement({ 
  children, 
  stroke = 'currentColor', 
  strokeWidth = 4,
}: {
  children: React.ReactNode;
  stroke?: string;
  strokeWidth?: number | string;
}) {
  // Garantir que stroke sempre tem um valor válido
  const finalStroke = stroke || 'currentColor';
  
  return (
    <g>
      {React.Children.map(children, (child, index) => {
        if (React.isValidElement(child)) {
          const elementProps: Record<string, unknown> = {
            key: child.key || `stroke-${index}`,
            stroke: finalStroke,
            strokeWidth,
            fill: 'none',
          };
          
          // Preservar outras props do elemento original
          if (child.props) {
            const childProps = child.props as Record<string, unknown>;
            Object.keys(childProps).forEach(key => {
              if (key !== 'stroke' && key !== 'strokeWidth' && key !== 'fill' && key !== 'key') {
                elementProps[key] = childProps[key];
              }
            });
          }
          
          return React.cloneElement(child as React.ReactElement<Record<string, unknown>>, elementProps);
        }
        return child;
      })}
    </g>
  );
}

// Componente específico para elementos com fill dinâmico
export function DynamicFillElement({ 
  children, 
  fill = 'currentColor', 
  ...props 
}: {
  children: React.ReactNode;
  fill?: string;
  [key: string]: unknown;
}) {
  return (
    <g fill={fill} {...props}>
      {children}
    </g>
  );
}

